from agent import *from models.products import *def process_productlist(data, context, session):    prods = data.xpath("//div[@class='ee-grid__item ee-loop__item']")    for prod in prods[:12]:        name = prod.xpath(".//h2//text()").string()        url = prod.xpath(".//a[@class='ee-post__title']/@href").string()        cat = prod.xpath(".//span[@class='ee-post__terms__link ee-term__link']//text()").string()        date = prod.xpath(".//li[@class='ee-post__meta ee-post__meta--date ee-post__metas__date']/text()[not(self::strong)]").string()        session.queue(Request(url, use='curl'), process_product, dict(context, name=name, url=url, cat=cat, date=date))    nexturl = data.xpath("//a[@class='ee-pagination__next page-numbers']//@href").string()    if nexturl:        session.queue(Request(nexturl, use='curl'),process_productlist, dict(context))def process_product(data, context, session):    product = Product()    product.name = context['name'].split("Review")[0]    product.ssid = context['url'].split('/')[-2]    product.category = context['cat'] or 'Games'    product.url = context['url']    review = Review()    review.title = context['name']    review.date = context['date']    review.ssid = product.ssid    review.type = 'pro'    review.url = context['url']    author_name = data.xpath("//li[@itemprop='author']/a//text()").string(multiple=True)    author_url = data.xpath("//li[@itemprop='author']/a//@href").string()    if author_name:        if author_url:            review.authors.append(Person(name=author_name, profile_url=author_url, ssid=author_name))        else:            review.authors.append(Person(name=author_name, ssid=author_name))    for xp in ["//body/p//text()", "//div[@class='elementor-widget-container']/div/p//text()", "//div[@class='elementor-widget-container']/p//text()"]:        excerpt = data.xpath(xp).string(multiple=True)        if excerpt:            if excerpt.split("ConsoleMonster.com is an")[0]:                review.properties.append(ReviewProperty(type='excerpt', value=excerpt.split("ConsoleMonster.com is an")[0]))                break    grade_overall = data.xpath("//div[@class='review-wu-grade-content']//span//text()").string()    if grade_overall:        review.grades.append(Grade(type='overall', value=float(grade_overall), best=10.0))    pros = data.xpath("//div[@class='pros']/ul/li//text()")    for pro in pros:        pro = pro.string().replace('+', '')        review.add_property(type='pros', value=pro)    cons = data.xpath("//div[@class='cons']/ul/li//text()")    for con in cons:        con = con.string().replace('- ', '')        review.add_property(type='cons', value=con)    if excerpt:        product.reviews.append(review)        session.emit(product)def run(context, session):    session.sessionbreakers = [SessionBreak(max_requests=3000)]    session.queue(Request("https://www.consolemonster.com/category/reviews/page/1",use='curl'), process_productlist, dict())